(function(){(async()=>{let e=document.getElementById(`status`);try{(await navigator.mediaDevices.getUserMedia({audio:{echoCancellation:!0,noiseSuppression:!0},video:!1})).getTracks().forEach(e=>e.stop()),e.textContent=`Microphone enabled! Closing...`,e.className=`status granted`,chrome.runtime.sendMessage({type:`MIC_PERMISSION_RESULT`,granted:!0}),setTimeout(()=>window.close(),800)}catch(t){let n=t.message||`Permission denied`;e.textContent=`Denied: ${n}`,e.className=`status denied`,chrome.runtime.sendMessage({type:`MIC_PERMISSION_RESULT`,granted:!1,error:n}),setTimeout(()=>window.close(),2e3)}})()})();